import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const formatDate = (value) => {
  if (!value) return '—';
  return new Date(value).toLocaleDateString();
};

const UserBookingList = ({ bookings, setBookings, setEditingBooking }) => {
  const { user } = useAuth();

  const handleDelete = async (bookingId) => {
    if (!user) return;
    const confirmDelete = window.confirm('Are you sure you want to cancel this booking?');
    if (!confirmDelete) return;

    try {
      await axiosInstance.delete(`/api/bookings/${bookingId}`, {
        headers: { Authorization: `Bearer ${user.token}` },
      });
      setBookings(bookings.filter((booking) => booking._id !== bookingId));
    } catch (error) {
      alert('Failed to delete booking.');
    }
  };

  if (!bookings.length) {
    return <p className="text-center text-[#0d2440] font-medium">No bookings yet. Create one above!</p>;
  }

  return (
    <div className="space-y-4">
      {bookings.map((booking) => (
        <div
          key={booking._id}
          className="bg-white/90 border border-[#c8e1fb] rounded-2xl p-5 drop-shadow-md flex flex-col md:flex-row md:items-center md:justify-between gap-4"
        >
          <div>
            <p className="text-sm uppercase tracking-widest text-[#546b86]">
              {booking.serviceType} &middot; {booking.propertyType}
            </p>
            <p className="text-lg font-semibold text-[#0d2440]">Pick up: {booking.pickupAddress}</p>
            <p className="text-[#0d2440]">Destination: {booking.destinationAddress}</p>
            <p className="text-sm text-[#546b86] mt-1">
              {formatDate(booking.date)} at {booking.time || '—'}
            </p>
            {booking.remarks && (
              <p className="text-sm text-[#546b86] mt-1">Remark: {booking.remarks}</p>
            )}
          </div>
          <div className="flex gap-3">
            <button
              onClick={() => setEditingBooking(booking)}
              className="px-4 py-2 rounded-full bg-[#F3FAFF] text-[#0d2440] font-semibold hover:bg-[#dbeafe] transition"
            >
              Edit
            </button>
            <button
              onClick={() => handleDelete(booking._id)}
              className="px-4 py-2 rounded-full bg-[#f87171] text-white font-semibold hover:bg-[#dc2626] transition"
            >
              Cancel
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

export default UserBookingList;
